1	/* layout.h -- Storage layout computation for PL/SW compiler */
2	/* Walks DCL AST nodes to assign offsets, compute sizes, build type descriptors */
3	
4	#ifndef LAYOUT_H
5	#define LAYOUT_H
6	
7	#include "ast.h"
8	#include "symtab.h"
9	#include "types.h"
10	
11	/* --- Static address allocation --- */
12	
13	/* Base address for static variables in .data section */
14	#define STATIC_BASE 0x1000
15	
16	int layout_static_next;  /* next available static address */
17	
18	/* --- Frame layout state --- */
19	
20	int layout_frame_size;   /* total frame size for current procedure */
21	
22	/* --- Layout error state --- */
23	
24	int layout_err;
25	char *layout_errmsg;
26	
27	void layout_init(void) {
28	    layout_static_next = STATIC_BASE;
29	    layout_frame_size = 0;
30	    layout_err = 0;
31	    layout_errmsg = 0;
32	}
33	
34	void layout_error(char *msg) {
35	    layout_err = 1;
36	    layout_errmsg = msg;
37	}
38	
39	/* --- Compute the width of a DCL node --- */
40	/* Handles simple types, arrays, and records.
41	   For records, also builds a type descriptor.
42	   Returns the total width in bytes. */
43	
44	int layout_dcl_width(int node) {
45	    int w;
46	    int child;
47	    int fcount;
48	    int offset;
49	    int fw;
50	    int desc;
51	    int fbase;
52	
53	    if (node == NODE_NULL) return 0;
54	
55	    /* Record type: walk children to compute total size */
56	    if (nd_type[node] == TYPE_RECORD) {
57	        offset = 0;
58	        fcount = 0;
59	
60	        /* Allocate a type descriptor for this record */
61	        desc = td_alloc(TDESC_RECORD);
62	        if (desc >= 0) {
63	            fbase = desc * TDESC_FIELD_MAX;
64	
65	            child = nd_left[node];
66	            while (child != NODE_NULL && fcount < TDESC_FIELD_MAX) {
67	                fw = layout_dcl_width(child);
68	                if (fw == 0) fw = 3;  /* default to 24-bit */
69	
70	                td_fname[fbase + fcount] = nd_name[child];
71	                td_ftype[fbase + fcount] = nd_type[child];
72	                td_fwidth[fbase + fcount] = fw;
73	                td_foffset[fbase + fcount] = offset;
74	
75	                offset = offset + fw;
76	                fcount = fcount + 1;
77	                child = nd_next[child];
78	            }
79	
80	            td_count[desc] = fcount;
81	            td_size[desc] = offset;
82	        }
83	        return offset;
84	    }
85	
86	    /* Simple type width */
87	    w = type_width(nd_type[node]);
88	    if (w == 0) w = 3;  /* default to 24-bit for untyped */
89	
90	    /* Array: width = element_width * dimension */
91	    if (nd_ival[node] > 0) {
92	        w = w * nd_ival[node];
93	    }
94	
95	    return w;
96	}
97	
98	/* --- Lay out parameters for a procedure --- */
99	/* Parameters are at positive offsets from fp.
100	   COR24 calling convention: first arg at fp+9 (3 saved regs * 3 bytes).
101	   Subsequent args follow at increasing offsets. */
102	
103	#define PARAM_BASE_OFFSET 9  /* fp + 9 for first parameter */
104	
105	void layout_params(int first_param) {
106	    int p;
107	    int offset;
108	    int idx;
109	    int w;
110	
111	    p = first_param;
112	    offset = PARAM_BASE_OFFSET;
113	
114	    while (p != NODE_NULL) {
115	        w = type_width(nd_type[p]);
116	        if (w == 0) w = 3;
117	
118	        /* Insert parameter into symbol table */
119	        idx = sym_insert(nd_name[p], nd_type[p], w, STOR_AUTO);
120	        if (idx >= 0) {
121	            sym_offset[idx] = offset;
122	            sym_flags[idx] = sym_flags[idx] | SYM_F_PARAM;
123	        }
124	
125	        offset = offset + w;
126	        p = nd_next[p];
127	    }
128	}
129	
130	/* --- Lay out local declarations in a procedure body --- */
131	/* AUTOMATIC locals get negative offsets from fp.
132	   STATIC locals get addresses from the static area. */
133	
134	void layout_locals(int body_node) {
135	    int stmt;
136	    int w;
137	    int idx;
138	    int desc;
139	
140	    if (body_node == NODE_NULL) return;
141	
142	    /* Walk statements in the body block */
143	    stmt = nd_left[body_node];
144	    while (stmt != NODE_NULL) {
145	        if (nd_kind[stmt] == NODE_DCL) {
146	            w = layout_dcl_width(stmt);
147	
148	            /* Insert into symbol table */
149	            idx = sym_insert(nd_name[stmt], nd_type[stmt], w, nd_stor[stmt]);
150	            if (idx >= 0) {
151	                if (nd_stor[stmt] == STOR_STATIC) {
152	                    /* Static: assign address from static area */
153	                    sym_offset[idx] = layout_static_next;
154	                    layout_static_next = layout_static_next + w;
155	                } else {
156	                    /* Automatic: negative offset from fp */
157	                    layout_frame_size = layout_frame_size + w;
158	                    sym_offset[idx] = 0 - layout_frame_size;
159	                }
160	
161	                /* Set flags for compound types */
162	                if (nd_type[stmt] == TYPE_RECORD) {
163	                    sym_flags[idx] = sym_flags[idx] | SYM_F_RECORD;
164	                }
165	                if (nd_ival[stmt] > 0) {
166	                    sym_flags[idx] = sym_flags[idx] | SYM_F_ARRAY;
167	                }
168	            }
169	        }
170	        stmt = nd_next[stmt];
171	    }
172	}
173	
174	/* --- Lay out a complete procedure --- */
175	/* Enters a new scope, processes params and locals,
176	   returns the frame size. Does NOT exit the scope
177	   (caller should do that after codegen). */
178	
179	int layout_proc(int proc_node) {
180	    if (proc_node == NODE_NULL) return 0;
181	
182	    layout_frame_size = 0;
183	    sym_enter_scope();
184	
185	    /* Lay out parameters */
186	    layout_params(nd_left[proc_node]);
187	
188	    /* Lay out local declarations in body */
189	    layout_locals(nd_right[proc_node]);
190	
191	    return layout_frame_size;
192	}
193	
194	/* --- Lay out global declarations --- */
195	/* Top-level DCLs: STATIC get static addresses,
196	   others treated as static by default at global scope. */
197	
198	void layout_globals(int prog_node) {
199	    int child;
200	    int w;
201	    int idx;
202	
203	    if (prog_node == NODE_NULL) return;
204	
205	    child = nd_left[prog_node];
206	    while (child != NODE_NULL) {
207	        if (nd_kind[child] == NODE_DCL) {
208	            w = layout_dcl_width(child);
209	
210	            idx = sym_insert(nd_name[child], nd_type[child], w,
211	                             nd_stor[child] == STOR_AUTO ? STOR_STATIC : nd_stor[child]);
212	            if (idx >= 0) {
213	                sym_offset[idx] = layout_static_next;
214	                layout_static_next = layout_static_next + w;
215	
216	                if (nd_type[child] == TYPE_RECORD) {
217	                    sym_flags[idx] = sym_flags[idx] | SYM_F_RECORD;
218	                }
219	                if (nd_ival[child] > 0) {
220	                    sym_flags[idx] = sym_flags[idx] | SYM_F_ARRAY;
221	                }
222	            }
223	        }
224	        child = nd_next[child];
225	    }
226	}
227	
228	/* --- Debug output --- */
229	
230	void layout_print_frame(void) {
231	    uart_putstr("  frame_size=");
232	    print_int(layout_frame_size);
233	    uart_putstr(" static_next=0x");
234	    /* Print hex manually */
235	    int v = layout_static_next;
236	    int d3 = v / 4096;
237	    int d2 = (v / 256) % 16;
