285	    nd_print(n, depth);
286	    /* PROC: dump params then body with labels */
287	    if (nd_kind[n] == NODE_PROC) {
288	        /* Dump parameter list */
289	        p = nd_left[n];
290	        if (p != NODE_NULL) {
291	            d = 0;
292	            while (d < depth + 1) { uart_putstr("  "); d = d + 1; }
293	            uart_puts("(PARAMS)");
294	            while (p != NODE_NULL) {
295	                nd_print(p, depth + 2);
296	                p = nd_next[p];
297	            }
298	        }
299	        /* Dump body */
300	        if (nd_right[n] != NODE_NULL) {
301	            d = 0;
302	            while (d < depth + 1) { uart_putstr("  "); d = d + 1; }
303	            uart_puts("(BODY)");
304	            nd_dump(nd_right[n], depth + 2);
305	        }
306	        nd_dump(nd_next[n], depth);
307	        return;
308	    }
309	    nd_dump(nd_left[n], depth + 1);
310	    nd_dump(nd_right[n], depth + 1);
311	    /* IF: dump else branch stored in nd_ival */
312	    if (nd_kind[n] == NODE_IF && nd_ival[n] != NODE_NULL) {
313	        d = 0;
314	        while (d < depth + 1) { uart_putstr("  "); d = d + 1; }
315	        uart_puts("(ELSE)");
316	        nd_dump(nd_ival[n], depth + 1);
317	    }
318	    /* DO_COUNT: dump end expression stored in nd_ival */
319	    if (nd_kind[n] == NODE_DO_COUNT && nd_ival[n] != NODE_NULL) {
320	        d = 0;
321	        while (d < depth + 1) { uart_putstr("  "); d = d + 1; }
322	        uart_puts("(TO)");
323	        nd_dump(nd_ival[n], depth + 1);
324	    }
325	    nd_dump(nd_next[n], depth);
326	}
