/* Parse PROC name(params) OPTIONS(...) RETURNS(type); body END;
   Syntax:
     PROC NAME;                           -- no params, no options
     PROC NAME(A INT, B PTR);             -- with params
     PROC NAME OPTIONS(FREESTANDING);     -- with options
