        && cur_type != TOK_RETURNS && cur_type != TOK_SEMI) {
        if (!is_alpha(cur_text[0])) {
            parse_error("expected proc name");
            return NODE_NULL;
        }
        nlen = str_len(cur_text);
        name = arena_alloc(nlen + 1);
        if (name) str_copy(name, cur_text);
        parse_advance();
    }

