            if (cur_type == TOK_FREESTANDING) {
                opts = opts | OPT_FREESTANDING;
                parse_advance();
            } else if (cur_type == TOK_NAKED) {
                opts = opts | OPT_NAKED;
                parse_advance();
            } else if (cur_type == TOK_LEAF) {
                opts = opts | OPT_LEAF;
                parse_advance();
