    ast_init();
    sym_init();
    types_init();
    layout_init();
    emit_init();
    cg_init();
    cg_static_init();

    parse_init("DCL A INT(24) INIT(10); DCL B INT(24) INIT(20); DCL C BYTE INIT(42);");
    prog = parse_program();
    if (parse_err) {
        uart_putstr("  PARSE ERROR: ");
        uart_puts(parse_errmsg);
        errs = errs + 1;
    } else {
        layout_globals(prog);
        cg_emit_static_data(prog);
        uart_putstr(emit_output());
