    ast_init();
    sym_init();
    types_init();
    layout_init();
    emit_init();
    cg_init();
    cg_static_init();

    parse_init("DCL BUF(8) BYTE;");
    prog = parse_program();
    if (parse_err) {
        uart_putstr("  PARSE ERROR: ");
        uart_puts(parse_errmsg);
        errs = errs + 1;
    } else {
        layout_globals(prog);
        cg_emit_static_data(prog);
        uart_putstr(emit_output());
    }

    /* Test 7: String literal registration and emission */
    uart_puts("--- static: string literal ---");
