char *str_find(char *haystack, char *needle) {
    char *h;
    char *n;
    char *start;

    if (!*needle) return haystack;

    start = haystack;
    while (*start) {
        h = start;
        n = needle;
        while (*h && *n && *h == *n) {
            h = h + 1;
            n = n + 1;
        }
        if (!*n) return start;
        start = start + 1;
    }
