    emit_zero();
    uart_putstr(emit_output());

    /* Test 12: error flag on buffer full (just check it's 0 normally) */
    uart_puts("--- error check ---");
    uart_putstr("  err=");
    print_int(emit_err);
    uart_putchar(10);
}

