    cg_assign(asgn);
    uart_putstr(emit_output());
    if (cg_err) { uart_puts("  FAIL: cg_err set"); errs = errs + 1; }

    /* Test 10: Large offset variable (outside 8-bit range) */
    uart_puts("--- asgn: large offset ---");
    arena_init();
    ast_init();
    sym_init();
    emit_init();
    cg_init();
